  // Fold icmp pred (X / C), X
  {
    auto FoldDivDividend = [&](BinaryOperator *Div, Value *Dividend,
                               bool IsSwapped) -> Instruction * {
      const APInt *Divisor;
      Value *X;
      if (!match(Div->getOperand(1), m_APInt(Divisor)))
        return nullptr;
      X = Div->getOperand(0);
      if (X != Dividend)
        return nullptr;
      // Divisor must not be 0, 1, -1 (division by 0 is poison, 1 identity, -1 may overflow)
      if (Divisor->isZero() || Divisor->isOne() ||
          (Div->getOpcode() == Instruction::SDiv && Divisor->isAllOnes()))
        return nullptr;
      bool IsSigned = Div->getOpcode() == Instruction::SDiv;
      // For signed division, divisor must be >1 or <-1? We'll handle both.
      // For now, only handle divisor > 1 for both signed and unsigned.
      // TODO: extend to negative divisor.
      if (IsSigned && Divisor->isNegative())
        return nullptr;
      // Map predicate
      ICmpInst::Predicate NewPred = Pred;
      if (IsSwapped)
        NewPred = ICmpInst::getSwappedPredicate(NewPred);
      // Determine relationship: (X / C) PRED X
      // If C > 1:
      // (X / C) <  X  <=> X > 0
      // (X / C) <= X  <=> X >= 0
      // (X / C) >  X  <=> X < 0
      // (X / C) >= X  <=> X <= 0
      // Equality: (X / C) == X <=> X == 0
      // Inequality: (X / C) != X <=> X != 0
      // For unsigned, same mapping.
      switch (NewPred) {
      case ICmpInst::ICMP_SLT:
      case ICmpInst::ICMP_ULT:
        return new ICmpInst(IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT,
                            X, ConstantInt::get(X->getType(), 0));
      case ICmpInst::ICMP_SLE:
      case ICmpInst::ICMP_ULE:
        return new ICmpInst(IsSigned ? ICmpInst::ICMP_SGE : ICmpInst::ICMP_UGE,
                            X, ConstantInt::get(X->getType(), 0));
      case ICmpInst::ICMP_SGT:
      case ICmpInst::ICMP_UGT:
        return new ICmpInst(IsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT,
                            X, ConstantInt::get(X->getType(), 0));
      case ICmpInst::ICMP_SGE:
      case ICmpInst::ICMP_UGE:
        return new ICmpInst(IsSigned ? ICmpInst::ICMP_SLE : ICmpInst::ICMP_ULE,
                            X, ConstantInt::get(X->getType(), 0));
      case ICmpInst::ICMP_EQ:
        return new ICmpInst(ICmpInst::ICMP_EQ,
                            X, ConstantInt::get(X->getType(), 0));
      case ICmpInst::ICMP_NE:
        return new ICmpInst(ICmpInst::ICMP_NE,
                            X, ConstantInt::get(X->getType(), 0));
      default:
        return nullptr;
      }
    };
    if (BO0 && (BO0->getOpcode() == Instruction::SDiv ||
                BO0->getOpcode() == Instruction::UDiv)) {
      if (Instruction *NewI = FoldDivDividend(BO0, Op1, /*IsSwapped*/ false))
        return NewI;
    }
    if (BO1 && (BO1->getOpcode() == Instruction::SDiv ||
                BO1->getOpcode() == Instruction::UDiv)) {
      if (Instruction *NewI = FoldDivDividend(BO1, Op0, /*IsSwapped*/ true))
        return NewI;
    }
  }

