+      // (X op C) <  X  <=> X > 0
+      // (X op C) <= X  <=> X >= 0
+      // (X op C) >  X  <=> X < 0
+      // (X op C) >= X  <=> X <= 0
+      // Equality: (X op C) == X <=> X == 0
+      // Inequality: (X op C) != X <=> X != 0
