+                BO0->getOpcode() == Instruction::UDiv ||
+                BO0->getOpcode() == Instruction::AShr ||
+                BO0->getOpcode() == Instruction::LShr)) {
+      if (Instruction *NewI = FoldDivShrDividend(BO0, Op1, /*IsSwapped*/ false))
+        return NewI;
+    }
+    if (BO1 && (BO1->getOpcode() == Instruction::SDiv ||
+                BO1->getOpcode() == Instruction::UDiv ||
+                BO1->getOpcode() == Instruction::AShr ||
+                BO1->getOpcode() == Instruction::LShr)) {
+      if (Instruction *NewI = FoldDivShrDividend(BO1, Op0, /*IsSwapped*/ true))
+        return NewI;
+    }
+  }

